import { derived } from 'svelte/store';
import { cursor } from './cursor';
import { gamePaused, gameStore } from './game';

export const keyboardDisabled = derived(
	[cursor, gameStore, gamePaused],
	([$cursor, $gameStore, $gamePaused]) => {
		return ($cursor.x === null && $cursor.y === null) || $gameStore.puzzleGrid[$cursor.y][$cursor.x] !== 0 || $gamePaused;
	},
	false,
);
